"""
Aplicativo completo de atualização de preços - arquivo único.
Uso: python app_completo.py
"""
import base64
import importlib.util
import io
import os
import re
import sys
import tempfile
import zlib
from difflib import SequenceMatcher

import openpyxl
from flask import request, jsonify, render_template_string
import jinja2

# ═══════════════════════════════════════════════════════════════════
# Embedded data (compressed + base64)
# ═══════════════════════════════════════════════════════════════════
_PYC_B64 = """

"""

_HTML_B64 = """

"""

# ═══════════════════════════════════════════════════════════════════
# Bootstrap: decode .pyc, load module, extract Flask app
# ═══════════════════════════════════════════════════════════════════
def _decode(b64_str):
    return zlib.decompress(base64.b64decode(b64_str.strip()))

_pyc_bytes = _decode(_PYC_B64)
_html_bytes = _decode(_HTML_B64)
INDEX_HTML = _html_bytes.decode('utf-8')

_tmpdir = tempfile.mkdtemp(prefix='webapp_')
_pyc_path = os.path.join(_tmpdir, 'app.cpython-314.pyc')
with open(_pyc_path, 'wb') as _f:
    _f.write(_pyc_bytes)

spec = importlib.util.spec_from_file_location('app', _pyc_path)
mod = importlib.util.module_from_spec(spec)
spec.loader.exec_module(mod)

app = mod.app
app.jinja_loader = jinja2.DictLoader({'index.html': INDEX_HTML})

# ═══════════════════════════════════════════════════════════════════
# Monkey-patch ler_grad for new 10-column Excel format
# ═══════════════════════════════════════════════════════════════════
_original_ler_grad = mod.ler_grad


def _adapt_grad_xlsx(file_bytes):
    wb = openpyxl.load_workbook(io.BytesIO(file_bytes), data_only=True)
    ws = wb.active
    header2 = str(ws.cell(1, 2).value or '').strip().upper()
    if 'DURA' not in header2:
        return file_bytes
    ws.delete_cols(2)
    buf = io.BytesIO()
    wb.save(buf)
    return buf.getvalue()


def _patched_ler_grad(file_bytes):
    return _original_ler_grad(_adapt_grad_xlsx(file_bytes))


mod.ler_grad = _patched_ler_grad

# ═══════════════════════════════════════════════════════════════════
# Imports from compiled module
# ═══════════════════════════════════════════════════════════════════
ler_pos            = mod.ler_pos
wix3_get_all_items = mod.wix3_get_all_items
wix3_put_item      = mod.wix3_put_item
norm_pos_name      = mod.norm_pos_name
extract_dur        = mod.extract_dur
_strip_accents     = mod._strip_accents
_buscar_pos_wix    = mod._buscar_pos_wix

_SYS_KEYS = {'_id', '_createdDate', '_updatedDate', '_owner'}


# ═══════════════════════════════════════════════════════════════════
# Helper functions
# ═══════════════════════════════════════════════════════════════════
def _parse_chave(chave):
    if not chave:
        return None, None
    parts = chave.rsplit(' - ', 1)
    if len(parts) == 2:
        name = parts[0].strip()
        dur = extract_dur(parts[1].strip())
        if dur:
            return name, dur
    return chave.strip(), None


def _build_stripped(dados):
    return {(_strip_accents(n), d): v for (n, d), v in dados.items()}


def _fmt_price(val):
    if val is None:
        return None
    if isinstance(val, str):
        val = val.strip()
        if val.startswith('R$'):
            return val
        try:
            val = float(val.replace(',', '.'))
        except ValueError:
            return val
    if isinstance(val, (int, float)):
        v = int(val) if float(val) == int(val) else val
        return f'R$ {v}'
    return str(val)


def _clean_data(d):
    return {k: v for k, v in d.items() if k not in _SYS_KEYS}


_FALLBACK_DURS = ('6', '9', '12')


def _find(dados, stripped, curso, dur_str):
    if not curso or not dur_str:
        return None
    return _buscar_pos_wix(dados, stripped, curso, dur_str)


def _to_words(s):
    return set(w for w in re.sub(r'[^a-z0-9 ]', ' ', s).split() if len(w) >= 3)


def _fuzzy_find_name(dados, stripped, curso):
    norm = norm_pos_name(curso)
    sn = _strip_accents(norm)
    clean = re.sub(r'[^a-z0-9 ]', ' ', sn)
    clean = re.sub(r'\s+', ' ', clean).strip()

    excel_names = {}
    for (n, d) in dados:
        if n not in excel_names:
            cn = re.sub(r'[^a-z0-9 ]', ' ', _strip_accents(n))
            excel_names[n] = re.sub(r'\s+', ' ', cn).strip()

    if not clean:
        return None

    for en, en_clean in excel_names.items():
        if clean in en_clean or en_clean in clean:
            return en

    wix_words = _to_words(clean)
    if wix_words:
        best_overlap, best_en = 0.0, None
        for en, en_clean in excel_names.items():
            en_words = _to_words(en_clean)
            if not en_words:
                continue
            shorter, longer = (wix_words, en_words) if len(wix_words) <= len(en_words) else (en_words, wix_words)
            overlap = len(shorter & longer) / len(shorter)
            if overlap > best_overlap:
                best_overlap, best_en = overlap, en
        if best_overlap >= 0.60:
            return best_en

    best, best_r = None, 0.0
    for en, en_clean in excel_names.items():
        r = SequenceMatcher(None, clean, en_clean).ratio()
        if r > best_r:
            best, best_r = en, r
    if best_r >= 0.70:
        return best
    return None


def _find_fb(dados, stripped, curso, dur_str):
    if not curso:
        return None
    if dur_str:
        hit = _buscar_pos_wix(dados, stripped, curso, dur_str)
        if hit:
            return hit
    for alt in _FALLBACK_DURS:
        if alt != dur_str:
            hit = _buscar_pos_wix(dados, stripped, curso, alt)
            if hit:
                return hit

    alt_name = _fuzzy_find_name(dados, stripped, curso)
    if alt_name:
        if dur_str:
            hit = _buscar_pos_wix(dados, stripped, alt_name, dur_str)
            if hit:
                return hit
        for alt in _FALLBACK_DURS:
            if alt != dur_str:
                hit = _buscar_pos_wix(dados, stripped, alt_name, alt)
                if hit:
                    return hit
    return None


# ═══════════════════════════════════════════════════════════════════
# pos collection matching
# ═══════════════════════════════════════════════════════════════════
def _match_pos(dados, stripped):
    items = wix3_get_all_items('pos')
    matches, nao_enc = [], []

    for item in items:
        d = item.get('data', item) if isinstance(item, dict) else item
        iid   = d.get('_id', '')
        title = (d.get('title') or '').strip()
        ch1   = (d.get('chave1') or '').strip()
        dur1  = (d.get('duracao1') or '').strip()
        dur2  = (d.get('duracao2') or '').strip()

        if not ch1 and not dur1:
            continue

        found1, found2 = None, None
        dd1 = extract_dur(dur1) if dur1 else None
        dd2 = extract_dur(dur2) if dur2 else None

        if title and dd1:
            found1 = _find_fb(dados, stripped, title, dd1)
        if title and dd2:
            found2 = _find_fb(dados, stripped, title, dd2)

        if not found1 and not found2:
            nao_enc.append({'curso': title or ch1, 'chave': ch1,
                            'duracao1': dur1, 'duracao2': dur2})
            continue

        a1 = d.get('preco1') or ''
        a2 = d.get('preco2') or ''
        nv1 = _fmt_price(found1['balcao']) if found1 else None
        nv2 = _fmt_price(found2['balcao']) if found2 else None

        needs = False
        if nv1 and str(nv1) != str(a1):
            needs = True
        if nv2 and str(nv2) != str(a2):
            needs = True

        full = dict(d)
        if nv1:
            full['preco1'] = nv1
        if nv2:
            full['preco2'] = nv2

        matches.append({
            'curso': title, 'chave': ch1,
            'duracao1': dur1, 'duracao2': dur2,
            'atual1': a1, 'novo1': nv1,
            'atual2': a2, 'novo2': nv2,
            'needs_update': needs,
            '_id': iid, '_full_data': full,
        })

    att = sum(1 for m in matches if m['needs_update'])
    return {
        'matches': matches, 'nao_encontrado': nao_enc,
        'total_atualizar': att,
        'total_sem_mudanca': len(matches) - att,
        'total_nao_enc': len(nao_enc),
    }


# ═══════════════════════════════════════════════════════════════════
# PrecoPos collection matching
# ═══════════════════════════════════════════════════════════════════
def _match_precopos(dados, stripped):
    items = wix3_get_all_items('PrecoPos')
    matches, nao_enc = [], []

    for item in items:
        d = item.get('data', item) if isinstance(item, dict) else item
        iid    = d.get('_id', '')
        curso  = (d.get('curso') or '').strip()
        ch1    = (d.get('chave1') or '').strip()
        ch2    = (d.get('chave2') or '').strip()
        durao  = (d.get('durao') or '').strip()
        durao1 = (d.get('durao1') or '').strip()

        fvs, fvs1 = None, None

        if curso and durao:
            fvs = _find_fb(dados, stripped, curso, extract_dur(durao))
        if not fvs and ch1:
            n1, dd1 = _parse_chave(ch1)
            if n1 and dd1:
                fvs = _find_fb(dados, stripped, n1, dd1)

        if curso and durao1:
            fvs1 = _find_fb(dados, stripped, curso, extract_dur(durao1))
        if not fvs1 and ch2:
            n2, dd2 = _parse_chave(ch2)
            if n2 and dd2:
                fvs1 = _find_fb(dados, stripped, n2, dd2)

        if not fvs and not fvs1:
            nao_enc.append({'curso': curso or ch1, 'chave': ch1,
                            'durao': durao, 'durao1': durao1})
            continue

        a_vs  = d.get('valorSite') or ''
        a_vs1 = d.get('valorSite1') or ''
        nv_vs  = _fmt_price(fvs['balcao'])  if fvs  else None
        nv_vs1 = _fmt_price(fvs1['balcao']) if fvs1 else None

        needs = False
        if nv_vs  and str(nv_vs)  != str(a_vs):  needs = True
        if nv_vs1 and str(nv_vs1) != str(a_vs1): needs = True

        full = dict(d)
        if nv_vs:  full['valorSite']  = nv_vs
        if nv_vs1: full['valorSite1'] = nv_vs1

        matches.append({
            'curso': curso or ch1, 'durao': durao, 'durao1': durao1,
            'atual_vs': a_vs, 'novo_vs': nv_vs,
            'atual_vs1': a_vs1, 'novo_vs1': nv_vs1,
            'needs_update': needs,
            '_id': iid, '_full_data': full,
        })

    att = sum(1 for m in matches if m['needs_update'])
    return {
        'matches': matches, 'nao_encontrado': nao_enc,
        'total_atualizar': att,
        'total_sem_mudanca': len(matches) - att,
        'total_nao_enc': len(nao_enc),
    }


# ═══════════════════════════════════════════════════════════════════
# Flask routes for Wix3 Pos-Graduacao
# ═══════════════════════════════════════════════════════════════════
@app.route('/api/preview_wix3_pos', methods=['POST'])
def preview_wix3_pos():
    f = request.files.get('file')
    if not f:
        return jsonify({'error': 'Nenhum arquivo enviado'}), 400
    try:
        dados = ler_pos(f.read())
        stripped = _build_stripped(dados)
        return jsonify({
            'pos':       _match_pos(dados, stripped),
            'preco_pos': _match_precopos(dados, stripped),
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/atualizar_wix3_pos', methods=['POST'])
def atualizar_wix3_pos():
    f = request.files.get('file')
    if not f:
        return jsonify({'error': 'Nenhum arquivo enviado'}), 400
    try:
        dados = ler_pos(f.read())
        stripped = _build_stripped(dados)

        pos_r  = _match_pos(dados, stripped)
        preco_r = _match_precopos(dados, stripped)

        atualizados, erros, ultimo_erro = 0, 0, ''

        for col, result in [('pos', pos_r), ('PrecoPos', preco_r)]:
            for m in result['matches']:
                if not m['needs_update']:
                    continue
                try:
                    wix3_put_item(col, m['_id'], _clean_data(m['_full_data']))
                    atualizados += 1
                except Exception as e:
                    erros += 1
                    ultimo_erro = str(e)

        return jsonify({
            'atualizados': atualizados,
            'erros': erros,
            'ultimo_erro': ultimo_erro,
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


